const body = $input.first().json.body || $input.first().json;
const taskId = body.task_id || body.task?.id || body.payload?.id || '';

// Field ID: "Link da Gravação"
const LINK_FIELD_ID = '0100e278-0005-48d3-ad6e-d6b06d9de2d9';

const historyItems = body.history_items || [];
const fieldItem = historyItems.find(h =>
  h.field === 'custom_field' &&
  h.custom_field?.id === LINK_FIELD_ID &&
  h.after?.value
);

// Also check direct task field value
const taskFields = body.task?.custom_fields || [];
const directField = taskFields.find(f => f.id === LINK_FIELD_ID);

const loomUrl = fieldItem?.after?.value || directField?.value || '';
const prosseguir = taskId !== '' && loomUrl !== '' && loomUrl.includes('http');

return [{ json: { prosseguir, taskId, loomUrl } }];

const task = $input.first().json;
const loomUrl = $('Verificar Link Gravação').item.json.loomUrl;
const taskId = $('Verificar Link Gravação').item.json.taskId;

// Extract Loom video ID from URL
// Formats: https://www.loom.com/share/{id} or https://loom.com/share/{id}
const loomMatch = loomUrl.match(/loom\.com\/share\/([a-zA-Z0-9]+)/);
const loomId = loomMatch ? loomMatch[1] : '';

// Get existing data from task
const cf = task.custom_fields || [];
const getVal = (id) => {
  const f = cf.find(x => x.id === id);
  return f?.value ? String(f.value).trim() : '';
};

return [{ json: {
  taskId,
  loomUrl,
  loomId,
  taskName: task.name || '',
  taskDescription: task.description || ''
} }];

const html = $input.first().json.data || '';
const loomId = $('Preparar Dados').item.json.loomId;
const taskId = $('Preparar Dados').item.json.taskId;
const loomUrl = $('Preparar Dados').item.json.loomUrl;

let transcriptUrl = '';
let videoDownloadUrl = '';
let videoTitle = '';

// Try to extract __NEXT_DATA__ JSON
try {
  const nextDataMatch = html.match(/<script id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);
  if (nextDataMatch) {
    const nextData = JSON.parse(nextDataMatch[1]);
    const video = nextData?.props?.pageProps?.video || {};
    transcriptUrl = video.transcriptUrl || video.transcript_url || '';
    videoDownloadUrl = video.download_url || video.cdnUrl || video.cdn_url || '';
    videoTitle = video.title || video.name || '';
  }
} catch(e) {
  // JSON parse failed
}

// Fallback: try to find transcript URL in HTML directly
if (!transcriptUrl) {
  const transcriptMatch = html.match(/https:\/\/cdn\.loom\.com\/[^"'\s]*transcript[^"'\s]*\.(vtt|json)/);
  if (transcriptMatch) transcriptUrl = transcriptMatch[0];
}

// Fallback: find video CDN URL
if (!videoDownloadUrl) {
  const cdnMatch = html.match(/https:\/\/cdn\.loom\.com\/sessions\/[^"'\s]+\.mp4/);
  if (cdnMatch) videoDownloadUrl = cdnMatch[0];
}

const hasTranscript = !!transcriptUrl;
const hasVideo = !!videoDownloadUrl;

return [{ json: {
  taskId,
  loomId,
  loomUrl,
  videoTitle,
  transcriptUrl,
  videoDownloadUrl,
  hasTranscript,
  hasVideo
} }];

const vttText = $input.first().json.data || '';
const loomData = $('Extrair Dados Loom').item.json;

// Parse VTT format to plain text
const lines = vttText.split('\n');
const textLines = [];
let skipLine = false;

for (const line of lines) {
  const trimmed = line.trim();
  // Skip WEBVTT header, timestamps, and empty lines
  if (!trimmed || trimmed === 'WEBVTT' || trimmed.includes('-->') || /^\d+$/.test(trimmed)) {
    continue;
  }
  // Skip NOTE lines
  if (trimmed.startsWith('NOTE')) continue;
  textLines.push(trimmed);
}

const transcript = textLines.join(' ').replace(/\s+/g, ' ').trim();

return [{ json: {
  transcript,
  source: 'loom_native',
  taskId: loomData.taskId,
  loomId: loomData.loomId,
  videoTitle: loomData.videoTitle
} }];

const whisperData = $input.first().json;
const loomData = $('Extrair Dados Loom').item.json;

// Whisper returns text directly
const transcript = typeof whisperData === 'string' ? whisperData : (whisperData.text || whisperData.data || '');

return [{ json: {
  transcript,
  source: 'whisper',
  taskId: loomData.taskId,
  loomId: loomData.loomId,
  videoTitle: loomData.videoTitle
} }];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';

// Split briefing from JSON data
const parts = content.split('---JSON---');
const briefingText = parts[0].trim();
let structuredData = {};

if (parts[1]) {
  try {
    const jsonStr = parts[1].trim();
    structuredData = JSON.parse(jsonStr);
  } catch(e) {
    // Try to find JSON block in the text
    const jsonMatch = parts[1].match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { structuredData = JSON.parse(jsonMatch[0]); } catch(e2) {}
    }
  }
}

const taskId = $('Parse VTT para Texto').item?.json?.taskId || $('Formatar Transcrição Whisper').item?.json?.taskId || '';

return [{ json: {
  taskId,
  briefingText,
  cpf: structuredData.cpf || '',
  rg: structuredData.rg || '',
  nomeCliente: structuredData.nome_cliente || '',
  numeroAit: structuredData.numero_ait || '',
  orgaoAutuador: structuredData.orgao_autuador || '',
  dataInfracao: structuredData.data_infracao || '',
  valorContrato: structuredData.valor_contrato || '',
  formaPagamento: structuredData.forma_pagamento || '',
  cnhNumero: structuredData.cnh_numero || '',
  endereco: structuredData.endereco || ''
} }];

const data = $input.first().json;

// Map of field ID -> value to update
const updates = [];

// CPF field: 26b4ecd6-6963-4160-a554-30cd4f36a70c
if (data.cpf) updates.push({ fieldId: '26b4ecd6-6963-4160-a554-30cd4f36a70c', value: data.cpf });

// RG field: f36e9cb0-f9d2-4cb8-91ea-e5014a2566c7
if (data.rg) updates.push({ fieldId: 'f36e9cb0-f9d2-4cb8-91ea-e5014a2566c7', value: data.rg });

// CNH number: cbefb914-0e29-4611-b992-b689d0b0fbb1
if (data.cnhNumero) updates.push({ fieldId: 'cbefb914-0e29-4611-b992-b689d0b0fbb1', value: data.cnhNumero });

// Endereço: 7eae45ba-94b4-4cb4-bd1b-927ef11b8107
if (data.endereco) updates.push({ fieldId: '7eae45ba-94b4-4cb4-bd1b-927ef11b8107', value: data.endereco });

// AIT number: e220c08f-03dd-487a-a8a2-6cf25e5bf9d3
if (data.numeroAit) updates.push({ fieldId: 'e220c08f-03dd-487a-a8a2-6cf25e5bf9d3', value: data.numeroAit });

// Data infração: ad630128-2859-40e7-a45a-a7639dfbce34
// (skip - requires timestamp format)

return updates.map(u => ({ json: { taskId: data.taskId, fieldId: u.fieldId, value: u.value } }));
